# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;
    public float damageMultiplier = 1f;
    public float priceMultiplier = 1f;

    private void Update()
    {
        if (Input.GetMouseButtonDown(0))
        {
            TakeDamage(10);
        }
    }

    public void TakeDamage(int amount)
    {
        health -= (int)(amount * damageMultiplier);
        Debug.Log("Player Health: " + health);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Player Currency: " + currency);
    }

    public int GetPrice(int itemCost)
    {
        return (int)(itemCost * priceMultiplier);
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;
    public int[] shopItems = new int[5];
    public string[] shopItemNames = new string[5];

    private void Start()
    {
        for (int i = 0; i < shopItems.Length; i++)
        {
            Debug.Log("Shop Item " + (i + 1) + ": " + shopItemNames[i] + ", Cost: " + GetPrice(shopItems[i]));
        }
    }

    public int GetPrice(int itemCost)
    {
        return playerStats.GetPrice(itemCost);
    }

    public void BuyItem(int index)
    {
        if (playerStats.currency >= shopItems[index])
        {
            playerStats.AddCurrency(-shopItems[index]);
            // Add item to player
            Debug.Log("Bought " + shopItemNames[index] + "!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }
}